    ].join('')
    def splitMarker = "set parallel_pipeline_task_num=2;"
    def splitIdx = seedSql.indexOf(splitMarker)
    assertTrue(splitIdx > 0)

    sql "set enable_decimal256=true"
    multi_sql """
        drop table if exists table_50_undef_partitions2_keys3_properties4_distributed_by5;
        drop table if exists table_50_undef_partitions2_keys3_properties4_distributed_by51;
        drop table if exists table_50_undef_partitions2_keys3_properties4_distributed_by52;
        drop table if exists table_50_undef_partitions2_keys3_properties4_distributed_by53;
        drop table if exists table_50_undef_partitions2_keys3_properties4_distributed_by54;
        drop table if exists table_50_undef_partitions2_keys3_properties4_distributed_by55;
        drop table if exists table_50_undef_partitions2_keys3_properties4_distributed_by56;
        drop table if exists table_50_undef_partitions2_keys3_properties4_distributed_by57;
    """
    sql seedSql.substring(0, splitIdx)

    def querySql = seedSql.substring(splitIdx + splitMarker.length()).trim()
    if (querySql.endsWith(";")) {
        querySql = querySql.substring(0, querySql.length() - 1)
    }

    def settingPairs = [
        [false, true],
        [true, true]
    ]

    for (def settingPair in settingPairs) {
        def disableJoinReorder = settingPair[0]
        def forceToLocalShuffle = settingPair[1]

        for (def parallelFragmentExecInstanceNum in [1, 2, 4]) {
            for (def parallelPipelineTaskNum in [2, 4, 8, 16, 32]) {
                multi_sql """
                    set enable_nereids_distribute_planner=true;
                    set enable_pipeline_x_engine=true;
                    set enable_local_shuffle=true;
                    set disable_join_reorder=${disableJoinReorder};
                    set force_to_local_shuffle=${forceToLocalShuffle};
                    set enable_sql_cache=false;
                    set enable_query_cache=false;
                    set query_cache_type=0;
                    set parallel_fragment_exec_instance_num=${parallelFragmentExecInstanceNum};
                    set parallel_pipeline_task_num=${parallelPipelineTaskNum};
                """

                List<List<Object>> baselineRows = null
                for (def i in 1..10) {
                    def rows = sql """${querySql}"""
                    assertEquals(805, rows.size())
                    rows.each { row ->
                        assertEquals(1, row.size())
                        assertEquals(2L, ((Number) row.get(0)).longValue())
                    }
                    if (baselineRows == null) {
                        baselineRows = rows
                    } else {
                        assertEquals(baselineRows, rows)
                    }
                }
            }
        }
    }
